sys_script.script:
(function executeRule(current, previous /*null when async*/ ) {

   (function executeRule(current, previous) {

    //gs.info("BR TRIGGERED");

    if (!current.workspace) {
       // gs.info("Workspace is EMPTY");
        return;
    }

    //gs.info("Workspace value: " + current.workspace);

    var workspace = current.workspace.getRefRecord();

    if (!workspace.isValidRecord()) {
        //gs.info("Workspace record NOT found");
        return;
    }

   //gs.info("Workspace found: " + workspace.number);

    //gs.info("Reservation Status: " + current.reservation_status);
    if (current.reservation_status == 'pending_check_in' || 
        current.reservation_status == 'checked_in') {

        workspace.status = 'unavailable';
       // gs.info("Setting workspace to UNAVAILABLE");

    } 
    else if (current.reservation_status == 'checked_out' || 
             current.reservation_status == 'no_show' || 
             current.reservation_status == 'cancelled') {

        workspace.status = 'available';
       // gs.info("Setting workspace to AVAILABLE");
    }

    workspace.update();
   // gs.info("Workspace updated");

})(current, previous);




})(current, previous);
